// IsValid - returns whether credential is valid or not.
func (cred Credentials) IsValid() bool {
	if cred.Status == AccountOff {
		return false
	}
	return IsAccessKeyValid(cred.AccessKey) && IsSecretKeyValid(cred.SecretKey) && !cred.IsExpired()
}

